// This CSD strategy generates first-order logic (FOL) formulas using the provided parser and language model.
// It uses constrained steps to ensure the generated prefix is a complete FOL statement.
// The strategy prioritizes using {forall} and {exists} for quantifiers, followed by predicates and logical connectives.
// The loop continues until the maximum number of steps is reached or the generated prefix is complete.
// CSD_RATIONALE_END

generated := [];
var stepCounter := 0;
var hasValid := false;
while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  if hasValid && stepCounter == 1 && parser.IsCompletePrefix(generated)
  {
    // If we have found a valid prefix and it is complete, stop generating
    break;
  }

  var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
  generated := generated + [next];
  stepsLeft := newSteps;

  if parser.IsCompletePrefix(generated)
  {
    // If the generated prefix is complete, stop generating
    break;
  }

  if !parser.IsCompletePrefix(generated) && !hasValid
  {
    // Check if we can find a valid next token for the current prefix
    var validTokens := parser.ValidNextTokens(generated);
    hasValid := exists token :: token in validTokens && parser.ValidNextToken(generated, token);

    if hasValid
    {
      // If we can find a valid next token, continue with ConstrainedStep
      var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
      generated := generated + [next];
      stepsLeft := newSteps;
      stepCounter := stepCounter + 1;
    }
    else
    {
      // If we cannot find a valid next token, stop generating
      break;
    }
  }
}

